public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _small = null!;
    private TextAnalyzer _large = null!;

    [GlobalSetup]
    public void Setup()
    {
        _small = new TextAnalyzer("The quick brown fox jumps over the lazy dog");

        // ~1000 words
        var rng = new Random(42);
        var words = new string[1000];
        for (int i = 0; i < words.Length; i++)
            words[i] = new string((char)('a' + rng.Next(26)), rng.Next(1, 15));
        _large = new TextAnalyzer(string.Join(' ', words));
    }

    [Benchmark] public double AverageWordLength_Small() => _small.AverageWordLength();
    [Benchmark] public double AverageWordLength_Large() => _large.AverageWordLength();
    [Benchmark] public object WordLengthHistogram_Small() => _small.WordLengthHistogram();
    [Benchmark] public object WordLengthHistogram_Large() => _large.WordLengthHistogram();
    [Benchmark] public int UniqueWordCount_Small() => _small.UniqueWordCount();
    [Benchmark] public int UniqueWordCount_Large() => _large.UniqueWordCount();
}

